 } } \right)\left( {\matrix{
   a &amp; b  \cr 
   c &amp; d  \cr 

 } } \right)$$
<br><br>$$ \Rightarrow {A^2} = \left( {\matrix{
   {{a^2} + bc} &amp; {ab + bd}  \cr 
   {ac + cd} &amp; {bc + {d^2}}  \cr 

 } } \right)$$
<br><br>$$ \Rightarrow {a^2} + bc = 1,\,bc + {d^2} = 1$$
<br><br>$$ab + bd = ac + cd = 0$$
<br><br>$$c \ne 0\,\,\,\,\,b \ne 0$$
<br><br>$$ \Rightarrow a + d = 0 \Rightarrow Tr\left( A \right) = 0$$
<br><br>$$\left| A \right| = ad - bc =  - {a^2} - bc =  - 1$$
